package config

import (
	"fmt"
	"os"
	"path/filepath"
)

// defaultTOML is the content written by config init. It documents every field
// and produces VS Code .code-workspace files out of the box.
const defaultTOML = `# Files copied from the source worktree into newly-created worktrees.
[sync]
include = [
  ".claude/settings.local.json",
  ".env",
  ".env.docker-compose",
  ".vscode/settings.json",
  ".vscode/tasks.json",
  ".vscode/launch.json",
  ".vscode/extensions.json",
  ".vscode/*.code-snippets",
]

# Per-worktree artifact generated by treepad sync and treepad new.
# Remove this section to skip artifact generation (e.g. for JetBrains / Neovim).
[artifact]
filename = "{{.Slug}}-{{.Branch}}.code-workspace"
content = """
{
  "folders": [
    {{- range $i, $w := .Worktrees}}
    {{- if $i}},{{end}}
    {"name": "{{$w.Branch}}", "path": "{{$w.RelPath}}"}
    {{- end}}
  ]
}
"""

# Command run when --open is passed to treepad new.
# {{.ArtifactPath}} is the absolute path of the generated artifact, or the
# worktree directory when no [artifact] section is configured.
[open]
command = ["open", "{{.ArtifactPath}}"]

# Configuration for tp from-spec. Resolves a spec body (from --issue or
# --file), writes PROMPT.md into the worktree, and hands off to an agent.
# Pass --prompt "..." on the CLI to append custom instructions; otherwise
# the default body ends with "Implement the ticket."
# agent_command elements are text/template strings with data:
# .Spec, .Skills, .Branch, .Slug, .WorktreePath, .PromptPath, .Prompt.
[from_spec]
skills = []
agent_command = ["claude", "{{.PromptPath}}"]
`

// WriteDefault writes a config file populated with documented defaults.
// If global is true, writes to the global config path (XDG or $TREEPAD_CONFIG).
// Otherwise writes .treepad.toml in dir. Returns the path written.
func WriteDefault(dir string, global bool) (string, error) {
	var path string
	if global {
		p, err := GlobalConfigPath()
		if err != nil {
			return "", err
		}
		path = p
	} else {
		path = filepath.Join(dir, configFileName)
	}

	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return "", fmt.Errorf("create config directory: %w", err)
	}
	if err := os.WriteFile(path, []byte(defaultTOML), 0o644); err != nil {
		return "", fmt.Errorf("write config: %w", err)
	}
	return path, nil
}
